// Sliding window: keep last 10 messages
List<MessageParam> history = new ArrayList<>(conversationHistory);
if (history.size() > 10) {
    history = history.subList(history.size() - 10, history.size());
}

// Summarize when context grows too large
if (estimateTokens(history) > 50_000) {
    List<MessageParam> old = history.subList(0, history.size() / 2);
    String summary = summarize(old);  // one extra LLM call
    history = new ArrayList<>();
    history.add(MessageParam.builder()
        .role(Role.ASSISTANT)
        .content("[Prior context summary: " + summary + "]")
        .build());
    history.addAll(conversationHistory.subList(
        conversationHistory.size() / 2, conversationHistory.size()));
}

