// Orchestrator-worker: parallel implementation with review
public class RefactorOrchestrator {
    private final ChatClient analyzer;
    private final ChatClient implementer;
    private final ChatClient reviewer;

    public String refactor(String code) {
        // 1. Analyze
        Analysis analysis = analyzer.prompt()
            .system("Identify refactoring opportunities. JSON output.")
            .user(code).call().entity(Analysis.class);

        // 2. Implement each refactoring in parallel
        List<String> patches = analysis.refactorings()
            .parallelStream()
            .map(r -> implementer.prompt()
                .system("Apply one refactoring. Return only modified code.")
                .user(r.description() + "\n\n" + code)
                .call().content())
            .toList();

        // 3. Review and merge
        return reviewer.prompt()
            .system("Merge these refactored versions into the best combined result.")
            .user(String.join("\n---\n", patches))
            .call().content();
    }
}

