// Domain-specific: split Java files at class/method boundaries
public List<TextSegment> chunkJavaSource(String source, String filePath) {
    // Split on access modifier + type/method declaration
    String[] parts = source.split(
        "(?=\\n\\s*(?:public|private|protected|static)\\s+"
        + "(?:class|interface|record|void|\\w+\\s+\\w+\\s*\\())"
    );
    return Arrays.stream(parts)
        .filter(p -> p.strip().length() > 50)
        .map(p -> TextSegment.from(p.strip(),
            Metadata.from("source", filePath)))
        .toList();
}

